CREATE TABLE IF NOT EXISTS user_fcm_tokens (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE, token text NOT NULL, device_type text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(user_id, token));

CREATE TABLE IF NOT EXISTS store_secrets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), store_id uuid UNIQUE REFERENCES stores(id) ON DELETE CASCADE, zapi_enabled boolean DEFAULT false, zapi_instance text, zapi_token text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());

CREATE TABLE IF NOT EXISTS user_active_devices (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE, device_id text NOT NULL, last_active timestamptz DEFAULT now(), UNIQUE(user_id, device_id));

CREATE TABLE IF NOT EXISTS refund_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_id uuid REFERENCES orders(id) ON DELETE CASCADE, user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE, reason refund_reason NOT NULL, description text, status refund_status DEFAULT 'pending', type refund_type DEFAULT 'full', amount numeric, admin_notes text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());